import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { motion, useScroll, useTransform } from 'framer-motion';
import { 
  FaHardHat, 
  FaUsers, 
  FaFileContract, 
  FaIndustry,
  FaCheckCircle,
  FaAward,
  FaChartLine,
  FaRocket,
  FaStar,
  FaShieldAlt,
  FaBolt,
  FaMoon,
  FaSun
} from 'react-icons/fa';
import './Home.css';

const Home = () => {
  const [darkMode, setDarkMode] = useState(false);
  const { scrollY } = useScroll();
  const y1 = useTransform(scrollY, [0, 300], [0, 100]);
  const y2 = useTransform(scrollY, [0, 300], [0, -100]);
  const opacity = useTransform(scrollY, [0, 300], [1, 0]);

  useEffect(() => {
    if (darkMode) {
      document.body.classList.add('dark');
    } else {
      document.body.classList.remove('dark');
    }
  }, [darkMode]);

  return (
    <main className="overflow-hidden">
      {/* Dark Mode Toggle */}
      <motion.button
        onClick={() => setDarkMode(!darkMode)}
        className="fixed top-20 right-8 z-50 p-4 glass rounded-full hover-lift"
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.9 }}
      >
        {darkMode ? <FaSun className="text-yellow-400 text-xl" /> : <FaMoon className="text-slate-700 text-xl" />}
      </motion.button>

      {/* Enhanced Hero Section with 3D Parallax */}
      <section className="hero-modern relative min-h-screen flex items-center justify-center overflow-hidden">
        {/* Animated Background Gradients */}
        <div className="absolute inset-0 bg-gradient-to-br from-blue-600 via-purple-600 to-pink-500 animate-gradient bg-[length:400%_400%]"></div>

        {/* Floating Geometric Shapes */}
        <motion.div 
          style={{ y: y1 }}
          className="absolute top-20 left-10 w-72 h-72 bg-blue-500/20 rounded-full blur-3xl"
        />
        <motion.div 
          style={{ y: y2 }}
          className="absolute bottom-20 right-10 w-96 h-96 bg-purple-500/20 rounded-full blur-3xl"
        />

        {/* Grid Overlay */}
        <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,')] opacity-30"></div>

        <div className="container relative z-10 px-6">
          <motion.div 
            className="text-center max-w-5xl mx-auto"
            initial={{ opacity: 0, y: 50 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
            style={{ opacity }}
          >
            {/* Badge */}
            <motion.div
              initial={{ opacity: 0, scale: 0.5 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ delay: 0.2 }}
              className="inline-flex items-center gap-2 px-6 py-3 mb-8 glass rounded-full text-white"
            >
              <FaRocket className="text-yellow-400" />
              <span className="font-medium">India's Leading Construction Partner</span>
              <FaStar className="text-yellow-400" />
            </motion.div>

            <h1 className="text-6xl md:text-7xl lg:text-8xl font-bold text-white mb-6 leading-tight">
              Building Tomorrow's
              <span className="block mt-2 gradient-text bg-gradient-to-r from-yellow-200 via-pink-200 to-blue-200">
                Infrastructure Today
              </span>
            </h1>

            <motion.p 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.4 }}
              className="text-xl md:text-2xl text-blue-100 mb-12 max-w-3xl mx-auto font-light"
            >
              Pioneering Government Tenders & AAC Blocks Manpower Solutions 
              with cutting-edge technology and unmatched expertise
            </motion.p>

            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.6 }}
              className="flex flex-wrap gap-6 justify-center"
            >
              <Link 
                to="/services" 
                className="group relative px-8 py-4 bg-white text-blue-600 rounded-full font-semibold text-lg overflow-hidden hover-lift"
              >
                <span className="relative z-10 flex items-center gap-2">
                  Explore Services
                  <FaBolt className="group-hover:translate-x-1 transition-transform" />
                </span>
              </Link>
              <Link 
                to="/contact" 
                className="px-8 py-4 glass text-white rounded-full font-semibold text-lg border-2 border-white/30 hover-lift"
              >
                Get Started →
              </Link>
            </motion.div>

            {/* Floating Trust Badges */}
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.8 }}
              className="mt-16 flex flex-wrap items-center justify-center gap-8 text-white/80"
            >
              <div className="flex items-center gap-2">
                <FaShieldAlt className="text-2xl text-green-400" />
                <span>ISO Certified</span>
              </div>
              <div className="flex items-center gap-2">
                <FaAward className="text-2xl text-yellow-400" />
                <span>15+ Years</span>
              </div>
              <div className="flex items-center gap-2">
                <FaStar className="text-2xl text-yellow-400" />
                <span>500+ Projects</span>
              </div>
            </motion.div>
          </motion.div>
        </div>

        {/* Scroll Indicator */}
        <motion.div 
          animate={{ y: [0, 10, 0] }}
          transition={{ repeat: Infinity, duration: 1.5 }}
          className="absolute bottom-10 left-1/2 -translate-x-1/2 text-white/60"
        >
          <div className="w-6 h-10 border-2 border-white/40 rounded-full flex items-start justify-center p-2">
            <div className="w-1 h-3 bg-white/60 rounded-full" />
          </div>
        </motion.div>
      </section>

      {/* Modern Stats Section with Glass Cards */}
      <section className="py-20 relative -mt-20 z-20">
        <div className="container px-6">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {[
              { icon: FaFileContract, number: '500+', label: 'Tenders Completed', color: 'from-blue-500 to-cyan-500' },
              { icon: FaUsers, number: '2000+', label: 'Skilled Workers', color: 'from-purple-500 to-pink-500' },
              { icon: FaIndustry, number: '50+', label: 'AAC Plants', color: 'from-orange-500 to-red-500' },
              { icon: FaAward, number: '15+', label: 'Years Excellence', color: 'from-green-500 to-emerald-500' },
            ].map((stat, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5, delay: index * 0.1 }}
                viewport={{ once: true }}
                whileHover={{ scale: 1.05, rotateY: 5 }}
                className="glass-dark rounded-2xl p-8 text-center hover-lift perspective-card group"
              >
                <div className={`inline-flex items-center justify-center w-16 h-16 rounded-full bg-gradient-to-br ${stat.color} mb-4 group-hover:animate-float`}>
                  <stat.icon className="text-3xl text-white" />
                </div>
                <h3 className="text-4xl font-bold gradient-text mb-2">{stat.number}</h3>
                <p className="text-gray-400">{stat.label}</p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Futuristic Services Section */}
      <section className="py-32 bg-gradient-to-b from-transparent to-slate-50 dark:to-slate-900">
        <div className="container px-6">
          <motion.div 
            initial={{ opacity: 0, y: 30 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            className="text-center mb-16"
          >
            <h2 className="text-5xl md:text-6xl font-bold mb-6">
              Our <span className="gradient-text">Core Services</span>
            </h2>
            <p className="text-xl text-gray-600 dark:text-gray-400 max-w-2xl mx-auto">
              Comprehensive construction and manpower solutions powered by innovation
            </p>
          </motion.div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {[
              {
                icon: FaFileContract,
                title: 'Government Tenders',
                description: 'Specialized in bidding and executing government construction projects with complete documentation.',
                features: ['Tender Documentation', 'Project Execution', 'Compliance Management'],
                gradient: 'from-blue-600 to-cyan-600',
                featured: false
              },
              {
                icon: FaIndustry,
                title: 'AAC Blocks Manpower',
                description: 'Expert workforce solutions for AAC blocks manufacturing plants with trained personnel.',
                features: ['Skilled Operators', 'Plant Maintenance', 'Quality Control'],
                gradient: 'from-purple-600 to-pink-600',
                featured: true
              },
              {
                icon: FaHardHat,
                title: 'Construction Management',
                description: 'End-to-end construction project management from planning to execution.',
                features: ['Project Planning', 'Resource Management', 'Quality Assurance'],
                gradient: 'from-orange-600 to-red-600',
                featured: false
              }
            ].map((service, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5, delay: index * 0.1 }}
                viewport={{ once: true }}
                className={`relative group ${service.featured ? 'lg:-mt-8' : ''}`}
              >
                {service.featured && (
                  <div className="absolute -top-4 left-1/2 -translate-x-1/2 px-4 py-1 bg-gradient-to-r from-yellow-400 to-orange-500 text-white text-sm font-bold rounded-full">
                    Most Popular
                  </div>
                )}
                <div className={`h-full glass-dark rounded-3xl p-8 hover-lift ${service.featured ? 'ring-2 ring-purple-500 glow-effect' : ''}`}>
                  <div className={`inline-flex items-center justify-center w-20 h-20 rounded-2xl bg-gradient-to-br ${service.gradient} mb-6 group-hover:scale-110 transition-transform`}>
                    <service.icon className="text-4xl text-white" />
                  </div>

                  <h3 className="text-2xl font-bold mb-4 text-white">{service.title}</h3>
                  <p className="text-gray-400 mb-6">{service.description}</p>

                  <ul className="space-y-3 mb-8">
                    {service.features.map((feature, idx) => (
                      <li key={idx} className="flex items-center gap-3 text-gray-300">
                        <FaCheckCircle className={`text-lg bg-gradient-to-br ${service.gradient} rounded-full`} />
                        {feature}
                      </li>
                    ))}
                  </ul>

                  <Link 
                    to="/services" 
                    className={`inline-flex items-center gap-2 text-white font-semibold group-hover:gap-4 transition-all`}
                  >
                    Learn More 
                    <span className={`inline-block bg-gradient-to-r ${service.gradient} rounded-full p-1`}>→</span>
                  </Link>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Modern Why Choose Us Section */}
      <section className="py-32 relative overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-br from-blue-50 to-purple-50 dark:from-slate-900 dark:to-slate-800"></div>

        <div className="container px-6 relative z-10">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
            <motion.div
              initial={{ opacity: 0, x: -50 }}
              whileInView={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.8 }}
              viewport={{ once: true }}
            >
              <h2 className="text-5xl font-bold mb-6">
                Why Choose <span className="gradient-text">BuildPro</span>?
              </h2>
              <p className="text-xl text-gray-600 dark:text-gray-400 mb-12">
                With over 15 years of industry experience, we deliver unmatched 
                expertise in construction and manpower services.
              </p>

              <div className="space-y-6">
                {[
                  { title: 'Proven Track Record', desc: '500+ government projects completed successfully', icon: FaAward, color: 'blue' },
                  { title: 'Expert Workforce', desc: '2000+ trained and certified professionals', icon: FaUsers, color: 'purple' },
                  { title: 'Quality Assurance', desc: 'ISO certified processes and standards', icon: FaShieldAlt, color: 'green' },
                  { title: 'Timely Delivery', desc: '98% on-time project completion rate', icon: FaRocket, color: 'orange' }
                ].map((item, index) => (
                  <motion.div
                    key={index}
                    initial={{ opacity: 0, x: -20 }}
                    whileInView={{ opacity: 1, x: 0 }}
                    transition={{ delay: index * 0.1 }}
                    viewport={{ once: true }}
                    className="flex items-start gap-4 p-6 glass rounded-2xl hover-lift"
                  >
                    <div className={`flex-shrink-0 w-14 h-14 rounded-xl bg-gradient-to-br from-${item.color}-500 to-${item.color}-600 flex items-center justify-center`}>
                      <item.icon className="text-2xl text-white" />
                    </div>
                    <div>
                      <h4 className="text-xl font-bold mb-2 text-gray-900 dark:text-white">{item.title}</h4>
                      <p className="text-gray-600 dark:text-gray-400">{item.desc}</p>
                    </div>
                  </motion.div>
                ))}
              </div>

              <Link 
                to="/about" 
                className="inline-block mt-12 px-8 py-4 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-full font-semibold text-lg hover-lift"
              >
                Learn More About Us →
              </Link>
            </motion.div>

            <motion.div
              initial={{ opacity: 0, x: 50 }}
              whileInView={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.8 }}
              viewport={{ once: true }}
              className="relative"
            >
              <div className="glass-dark rounded-3xl p-12 aspect-square flex items-center justify-center hover-lift">
                <div className="text-center">
                  <FaChartLine className="text-9xl gradient-text mb-6 mx-auto animate-float" />
                  <p className="text-2xl font-bold text-white">Excellence in Every Project</p>
                </div>
              </div>

              {/* Floating Stats */}
              <motion.div 
                animate={{ y: [0, -10, 0] }}
                transition={{ repeat: Infinity, duration: 3 }}
                className="absolute -top-8 -right-8 glass rounded-2xl p-6 text-center"
              >
                <div className="text-3xl font-bold gradient-text">98%</div>
                <div className="text-sm text-gray-600 dark:text-gray-400">Success Rate</div>
              </motion.div>

              <motion.div 
                animate={{ y: [0, 10, 0] }}
                transition={{ repeat: Infinity, duration: 4 }}
                className="absolute -bottom-8 -left-8 glass rounded-2xl p-6 text-center"
              >
                <div className="text-3xl font-bold gradient-text">24/7</div>
                <div className="text-sm text-gray-600 dark:text-gray-400">Support</div>
              </motion.div>
            </motion.div>
          </div>
        </div>
      </section>

      {/* CTA Section */}
      <section className="cta-section">
        <div className="container">
          <motion.div 
            className="cta-content"
            initial={{ opacity: 0, y: 30 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
            viewport={{ once: true }}
          >
            <h2>Ready to Start Your Next Project?</h2>
            <p>Get in touch with our experts for a free consultation and quote</p>
            <Link to="/contact" className="btn btn-primary btn-lg">
              Contact Us Today
            </Link>
          </motion.div>
        </div>
      </section>
    </main>
  );
};

export default Home;
